import Ariadne
from graphql import GraphQLSchema

# Define the User type
User = Ariadne.ObjectType("User")
User.set_fields(
    username=Ariadne.Field(type=str, public=True),
    bio=Ariadne.Field(type=str, public=True),
    email=Ariadne.Field(type=str, private=True),
    phone=Ariadne.Field(type=str, private=True),
    address=Ariadne.Field(type=str, private=True)
)

# Define the Post type
Post = Ariadne.ObjectType("Post")
Post.set_fields(
    title=Ariadne.Field(type=str, public=True),
    content=Ariadne.Field(type=str, public=True)
)

# Define the Query type
Query = Ariadne.ObjectType("Query")
Query.set_fields(
    user=Ariadne.Field(type=User, args={"username": Ariadne.Argument(type=str)}),
    users=Ariadne.Field(type=[User], args={"limit": Ariadne.Argument(type=int)})
)

# Define the Mutation type
Mutation = Ariadne.ObjectType("Mutation")
Mutation.set_fields(
    createUser=Ariadne.Field(type=User, args={"username": Ariadne.Argument(type=str), "email": Ariadne.Argument(type=str)}),
    updateUser=Ariadne.Field(type=User, args={"id": Ariadne.Argument(type=str), "username": Ariadne.Argument(type=str)})
)

# Define the schema
schema = GraphQLSchema(query=Query, mutation=Mutation)